#include <bits/stdc++.h>
using namespace std;
int n,ans=0;
struct node
{
	int a1,h,c;
} a[405];
bitset<40005> dp;
bool fun(node x,node y)
{
	return x.a1<y.a1;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i].h>>a[i].a1>>a[i].c;
	sort(a+1,a+1+n,fun);
	dp[0]=true;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=a[i].c;j++)
		{
			for(int k=a[i].a1;k>=a[i].h;k--) dp[k]=dp[k]||dp[k-a[i].h],ans=max(ans,dp[k]?k:ans);
		}
	}
	cout<<ans;
	return 0;
}
